INSERT INTO posts (id, author_id, parent_id, body, is_deleted, deleted_at, created_at, updated_at) VALUES
 (1, 1, NULL, 'Spring Boot で @Transactional の境界、サービス層に付けるかリポジトリ層か、みんなどうしてる？', false, NULL, now() - interval '220 hours', now() - interval '220 hours'),
 (2, 2, NULL, 'React の useEffect の依存配列、ESLint の exhaustive-deps を入れてから事故が減った。', false, NULL, now() - interval '210 hours', now() - interval '210 hours'),
 (3, 3, NULL, 'PostgreSQL で LIKE の部分一致が遅い…pg_trgm の GIN インデックス試した人いる？', false, NULL, now() - interval '200 hours', now() - interval '200 hours'),
 (4, 4, NULL, '今日の昼、新しくできたカフェに行ってきた。エスプレッソが当たりだった。', false, NULL, now() - interval '190 hours', now() - interval '190 hours'),
 (5, 5, NULL, 'docker compose でローカルの DB ごと立てるようにしたら、環境構築が一気に楽になった。', false, NULL, now() - interval '180 hours', now() - interval '180 hours'),
 (6, 6, NULL, 'レコメンドの素振りで LightFM を触っている。タグを特徴量に入れられるのが便利。', false, NULL, now() - interval '170 hours', now() - interval '170 hours'),
 (7, 1, NULL, 'Java の record、DTO にすごく便利。ボイラープレートが消える。', false, NULL, now() - interval '160 hours', now() - interval '160 hours'),
 (8, 2, NULL, 'Flexbox と grid、未だにどっちを使うか毎回迷う。', false, NULL, now() - interval '150 hours', now() - interval '150 hours'),
 (9, 3, NULL, '週末に Switch の新作をやっていた。全然進捗が出ていない。', false, NULL, now() - interval '140 hours', now() - interval '140 hours'),
 (10, 5, NULL, '朝ランしてから出社すると頭が冴える気がする。', false, NULL, now() - interval '130 hours', now() - interval '130 hours'),
 (11, 1, NULL, 'Spring Security のセッション認証、思ったよりすんなり動いた。', false, NULL, now() - interval '120 hours', now() - interval '120 hours'),
 (12, 4, NULL, 'Figma のコンポーネントを整理した。デザインの再利用が捗る。', false, NULL, now() - interval '110 hours', now() - interval '110 hours'),
 (13, 6, NULL, '『リーダブルコード』を読み返している。やっぱり名前付けが大事。', false, NULL, now() - interval '100 hours', now() - interval '100 hours'),
 (14, 2, NULL, 'TypeScript の satisfies 演算子、型を緩めずに補完を効かせられて良い。', false, NULL, now() - interval '92 hours', now() - interval '92 hours'),
 (15, 3, NULL, 'JPA の N+1 問題、fetch join と EntityGraph どっちで対処してる？', false, NULL, now() - interval '84 hours', now() - interval '84 hours'),
 (16, 5, NULL, 'AWS のコスト、気づいたら地味に増えている。タグを付けて可視化したい。', false, NULL, now() - interval '76 hours', now() - interval '76 hours'),
 (17, 1, NULL, '新しい案件のキックオフだった。要件整理から丁寧にやっていきたい。', false, NULL, now() - interval '68 hours', now() - interval '68 hours'),
 (18, 6, NULL, '埋め込みベクトルでの類似検索、pgvector が手軽でいいらしい。', false, NULL, now() - interval '60 hours', now() - interval '60 hours'),
 (19, 4, NULL, 'デスクに小さいコーヒーミルを置いた。挽きたては違う。', false, NULL, now() - interval '52 hours', now() - interval '52 hours'),
 (20, 2, NULL, '状態管理、結局 TanStack Query でだいぶ済むようになった。', false, NULL, now() - interval '44 hours', now() - interval '44 hours'),
 (21, 3, NULL, 'EXPLAIN ANALYZE が読めるようになると、遅いクエリの原因がすぐ分かる。', false, NULL, now() - interval '36 hours', now() - interval '36 hours'),
 (22, 5, NULL, '間違えて投稿しちゃった、消します。', true, now() - interval '4 hours', now() - interval '5 hours', now() - interval '4 hours'),
