 -- 返信
 (23, 3, 1, 'サービス層に付けています。トランザクション境界＝ユースケース境界だと思っているので。', false, NULL, now() - interval '190 hours', now() - interval '190 hours'),
 (24, 2, 1, '自分もサービス層派。リポジトリに付けると粒度が細かすぎる気がする。', false, NULL, now() - interval '188 hours', now() - interval '188 hours'),
 (25, 1, 3, 'pg_trgm の GIN、効きましたよ。LIKE の前後%でもインデックスが使われるようになった。', false, NULL, now() - interval '150 hours', now() - interval '150 hours'),
 (26, 6, 3, '件数次第ですが、全文検索が必要なら別の手も検討の価値ありです。', false, NULL, now() - interval '148 hours', now() - interval '148 hours'),
 (27, 5, 4, 'そのカフェ気になってました、行ってみます。', false, NULL, now() - interval '185 hours', now() - interval '185 hours'),
 (28, 1, 15, 'EntityGraph を使っています。アノテーションで宣言的に書けるので。', false, NULL, now() - interval '80 hours', now() - interval '80 hours'),
 (29, 3, 6, 'LightFM いいですよね。ハイブリッドなのでコールドスタートにも比較的強い。', false, NULL, now() - interval '165 hours', now() - interval '165 hours'),
