-- ---------- post_tags (投稿へのタグ付け) ----------

-- ---------- follows (人のフォロー / nickname は付与者のみ可視) ----------

-- ---------- tag_follows (タグ/トピックのフォロー → タイムライン合成に効く) ----------

-- ---------- likes (1人1いいね = UNIQUE(user_id, post_id)) ----------

-- ---------- notifications (いいね・返信のみ / フォローは通知しない) ----------
-- recipient = 投稿の作者, actor = 操作した人

-- ---------- view_logs (閲覧履歴 / レコメンド・監査の土台, 非公開) ----------

-- ---------- シーケンスを採番済みの最大IDに合わせ直す ----------
-- （明示IDで入れたテーブルのみ。pg_get_serial_sequence は SERIAL / IDENTITY 両対応）
SELECT setval(pg_get_serial_sequence('users','id'),         (SELECT MAX(id) FROM users));
SELECT setval(pg_get_serial_sequence('tags','id'),          (SELECT MAX(id) FROM tags));
SELECT setval(pg_get_serial_sequence('posts','id'),         (SELECT MAX(id) FROM posts));
SELECT setval(pg_get_serial_sequence('user_tags','id'),     (SELECT MAX(id) FROM user_tags));
SELECT setval(pg_get_serial_sequence('post_tags','id'),     (SELECT MAX(id) FROM post_tags));
SELECT setval(pg_get_serial_sequence('follows','id'),       (SELECT MAX(id) FROM follows));
SELECT setval(pg_get_serial_sequence('tag_follows','id'),   (SELECT MAX(id) FROM tag_follows));
SELECT setval(pg_get_serial_sequence('likes','id'),         (SELECT MAX(id) FROM likes));
SELECT setval(pg_get_serial_sequence('notifications','id'), (SELECT MAX(id) FROM notifications));
SELECT setval(pg_get_serial_sequence('view_logs','id'),     (SELECT MAX(id) FROM view_logs));
